import { useEffect, useMemo, useState } from "react";
import api from "../api";

/** ========= Helpers ========= **/
const PAGE_SIZE = 10;
const STATUSES = ["ACTIVE", "INACTIVE"];

/** Chuẩn hoá Page<?> từ BE */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return {
        list: d?.content || [],
        pages: typeof d?.totalPages === "number" ? d.totalPages : 1,
    };
}

/** debounce nhỏ cho ô tìm kiếm */
function useDebounce(value, delay = 400) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

/** ========= API Roles tối thiểu (inline để không phải tạo file mới) ========= **/
async function fetchAllPermissions() {
    try {
        const { data } = await api.get("/api/roles/permissions");
        return Array.isArray(data) ? data : [];
    } catch {
        // fallback local nếu BE chưa có endpoint này
        return [
            // Khách hàng
            "CUSTOMER_READ", "CUSTOMER_CREATE", "CUSTOMER_UPDATE", "CUSTOMER_DELETE",
            // Hợp đồng
            "CONTRACT_READ", "CONTRACT_CREATE", "CONTRACT_UPDATE", "CONTRACT_APPROVE",
            // Thanh toán
            "PAYMENT_READ", "PAYMENT_CREATE", "PAYMENT_MARK_PAID", "PAYMENT_DELETE",
            // Báo cáo
            "REPORT_VIEW", "REPORT_EXPORT", "REPORT_FINANCE_VIEW",
            // Hệ thống
            "USER_MANAGE", "SYSTEM_CONFIG", "SYSTEM_AUDIT_VIEW",
            // Sự kiện/Marketing
            "EVENT_READ", "EVENT_CREATE", "MARKETING_CAMPAIGN_MANAGE",
        ];
    }
}

async function createCustomRole(name, permissions) {
    // Cần RoleController ở BE: POST /api/roles {name, permissions[]}
    const payload = { name, permissions };
    const { data } = await api.post("/api/roles", payload);
    return data; // {id, name, permissions...}
}

/** ========= Component chính: Users ========= **/
export default function Users() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [pages, setPages] = useState(1);
    const [q, setQ] = useState("");
    const dq = useDebounce(q);

    const [open, setOpen] = useState(false);
    const [editing, setEditing] = useState(null);

    async function load() {
        const { data } = await api.get("/api/users", {
            params: { page, size: PAGE_SIZE, q: dq || undefined },
        });
        const p = normalizePage(data);
        setRows(p.list);
        setPages(p.pages);
    }

    useEffect(() => { load(); }, [page, dq]);

    const openCreate = () => { setEditing(null); setOpen(true); };
    const openEdit = (u) => { setEditing(u); setOpen(true); };

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <h1 className="text-xl font-semibold">Người dùng</h1>
                <button className="px-3 py-2 rounded bg-indigo-600 text-white" onClick={openCreate}>
                    + Thêm người dùng
                </button>
            </div>

            <div className="flex items-center gap-2">
                <input
                    className="border px-3 py-2 rounded w-80"
                    placeholder="Tìm tên đăng nhập, họ tên, email..."
                    value={q}
                    onChange={(e) => { setQ(e.target.value); setPage(0); }}
                />
            </div>

            <div className="overflow-auto">
                <table className="min-w-[900px] border">
                    <thead>
                    <tr className="bg-gray-50">
                        <th className="p-2 border">ID</th>
                        <th className="p-2 border">Tên đăng nhập</th>
                        <th className="p-2 border">Họ tên</th>
                        <th className="p-2 border">Email</th>
                        <th className="p-2 border">Điện thoại</th>
                        <th className="p-2 border">Vai trò</th>
                        <th className="p-2 border">Trạng thái</th>
                        <th className="p-2 border">Hành động</th>
                    </tr>
                    </thead>
                    <tbody>
                    {rows.map((u) => (
                        <tr key={u.id}>
                            <td className="p-2 border">{u.id}</td>
                            <td className="p-2 border">{u.username}</td>
                            <td className="p-2 border">{u.fullName}</td>
                            <td className="p-2 border">{u.email}</td>
                            <td className="p-2 border">{u.phone}</td>
                            <td className="p-2 border">{u.role}</td>
                            <td className="p-2 border">{u.active ? "ACTIVE" : "INACTIVE"}</td>
                            <td className="p-2 border">
                                <button className="px-2 py-1 border rounded" onClick={() => openEdit(u)}>Sửa</button>
                                <button
                                    className="ml-2 px-2 py-1 border rounded text-red-600"
                                    onClick={async () => {
                                        if (!window.confirm("Xoá người dùng này?")) return;
                                        await api.delete(`/api/users/${u.id}`);
                                        await load();
                                    }}
                                >
                                    Xoá
                                </button>
                            </td>
                        </tr>
                    ))}
                    {rows.length === 0 && (
                        <tr>
                            <td className="p-4 text-gray-500" colSpan={8}>Không có dữ liệu</td>
                        </tr>
                    )}
                    </tbody>
                </table>
            </div>

            <div className="flex items-center gap-2">
                <button disabled={page === 0} onClick={() => setPage((p) => p - 1)} className="px-3 py-1 border rounded">
                    Trước
                </button>
                <div>Trang {page + 1}/{pages}</div>
                <button disabled={page + 1 >= pages} onClick={() => setPage((p) => p + 1)} className="px-3 py-1 border rounded">
                    Sau
                </button>
            </div>

            {open && (
                <UserModal
                    initial={editing}
                    onClose={() => setOpen(false)}
                    onSaved={async () => { setOpen(false); await load(); }}
                />
            )}
        </div>
    );
}

/** ========= Modal Thêm/Sửa + UI Phân quyền giống mockup ========= **/

function UserModal({ initial, onClose, onSaved }) {
    const isEdit = !!initial;
    const [form, setForm] = useState(() => ({
        username: initial?.username || "",
        fullName: initial?.fullName || "",
        email: initial?.email || "",
        phone: initial?.phone || "",
        password: "",
        active: initial?.active ?? true,
    }));

    // state từ RolePermissionPicker (mode, roleName, permissions[])
    const [permState, setPermState] = useState({ mode: "ADMIN", roleName: "ADMIN", permissions: [] });
    const canSubmit = form.username && (isEdit || form.password);

    const onChange = (k, v) => setForm((s) => ({ ...s, [k]: v }));

    const handleSubmit = async (e) => {
        e.preventDefault();

        let roleNameToUse = permState?.roleName || "ADMIN";

        // Nếu là TÙY CHỈNH thì tạo Role mới trước
        if (permState?.mode === "CUSTOM") {
            const name = `CUSTOM_${Date.now()}`;
            const created = await createCustomRole(name, permState?.permissions || []);
            roleNameToUse = created?.name || name;
        }

        const payload = {
            username: form.username,
            fullName: form.fullName || null,
            email: form.email || null,
            phone: form.phone || null,
            roleName: roleNameToUse,
            active: !!form.active,
        };
        if (!isEdit) payload.password = form.password;

        if (isEdit) await api.put(`/api/users/${initial.id}`, payload);
        else await api.post("/api/users", payload);

        onSaved?.();
    };

    return (
        <div className="fixed inset-0 bg-black/40 flex items-start justify-center z-50">
            <div className="bg-white w-[900px] max-h-[88vh] overflow-auto rounded-2xl shadow-xl mt-10">
                <div className="p-5 border-b text-lg font-semibold">
                    {isEdit ? "Sửa người dùng" : "Thêm người dùng mới"}
                </div>

                <form className="p-5 space-y-6" onSubmit={handleSubmit}>
                    {/* Hàng thông tin cơ bản */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="text-sm text-gray-600">Tên đăng nhập</label>
                            <input
                                className="mt-1 border px-3 py-2 rounded w-full"
                                value={form.username}
                                onChange={(e) => onChange("username", e.target.value)}
                                required
                            />
                        </div>
                        <div>
                            <label className="text-sm text-gray-600">Họ tên</label>
                            <input
                                className="mt-1 border px-3 py-2 rounded w-full"
                                value={form.fullName}
                                onChange={(e) => onChange("fullName", e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="text-sm text-gray-600">Email</label>
                            <input
                                type="email"
                                className="mt-1 border px-3 py-2 rounded w-full"
                                value={form.email}
                                onChange={(e) => onChange("email", e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="text-sm text-gray-600">Điện thoại</label>
                            <input
                                className="mt-1 border px-3 py-2 rounded w-full"
                                value={form.phone}
                                onChange={(e) => onChange("phone", e.target.value)}
                            />
                        </div>
                        {!isEdit && (
                            <div>
                                <label className="text-sm text-gray-600">Mật khẩu</label>
                                <input
                                    type="password"
                                    className="mt-1 border px-3 py-2 rounded w-full"
                                    value={form.password}
                                    onChange={(e) => onChange("password", e.target.value)}
                                    required
                                />
                            </div>
                        )}
                        <div>
                            <label className="text-sm text-gray-600">Trạng thái</label>
                            <select
                                className="mt-1 border px-3 py-2 rounded w-full"
                                value={form.active ? "ACTIVE" : "INACTIVE"}
                                onChange={(e) => onChange("active", e.target.value === "ACTIVE")}
                            >
                                {STATUSES.map((s) => (
                                    <option key={s} value={s}>{s}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    {/* Khối phân quyền chi tiết */}
                    <RolePermissionPicker onChange={setPermState} initialRoleName={initial?.role} />

                    <div className="flex items-center justify-end gap-2 pt-2 border-t">
                        <button type="button" onClick={onClose} className="px-4 py-2 rounded border">Hủy</button>
                        <button disabled={!canSubmit} className="px-4 py-2 rounded bg-indigo-600 text-white disabled:opacity-60">
                            Lưu
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

/** ========= UI Chọn vai trò/quyền (inline, không cần tạo file khác) ========= **/

const GROUPS = [
    {
        title: "Quản lý khách hàng", icon: "👥",
        items: [
            ["CUSTOMER_READ", "Xem danh sách khách hàng"],
            ["CUSTOMER_CREATE", "Tạo khách hàng mới"],
            ["CUSTOMER_UPDATE", "Chỉnh sửa thông tin khách hàng"],
            ["CUSTOMER_DELETE", "Xoá khách hàng"],
        ],
    },
    {
        title: "Quản lý hợp đồng", icon: "🧾",
        items: [
            ["CONTRACT_READ", "Xem danh sách hợp đồng"],
            ["CONTRACT_CREATE", "Tạo hợp đồng mới"],
            ["CONTRACT_UPDATE", "Chỉnh sửa hợp đồng"],
            ["CONTRACT_APPROVE", "Phê duyệt hợp đồng"],
        ],
    },
    {
        title: "Quản lý thanh toán", icon: "💰",
        items: [
            ["PAYMENT_READ", "Xem thông tin thanh toán"],
            ["PAYMENT_CREATE", "Tạo phiếu thu"],
            ["PAYMENT_MARK_PAID", "Phê duyệt thanh toán"],
            ["PAYMENT_DELETE", "Xoá phiếu (chưa thanh toán)"],
        ],
    },
    {
        title: "Báo cáo & Thống kê", icon: "📊",
        items: [
            ["REPORT_VIEW", "Xem báo cáo tổng hợp"],
            ["REPORT_EXPORT", "Xuất báo cáo"],
            ["REPORT_FINANCE_VIEW", "Xem báo cáo tài chính"],
        ],
    },
    {
        title: "Quản trị hệ thống", icon: "⚙️",
        items: [
            ["USER_MANAGE", "Quản lý người dùng"],
            ["SYSTEM_CONFIG", "Cấu hình hệ thống"],
            ["SYSTEM_AUDIT_VIEW", "Xem nhật ký hệ thống"],
        ],
    },
    {
        title: "Marketing & Sự kiện", icon: "🎯",
        items: [
            ["EVENT_READ", "Xem danh sách sự kiện"],
            ["EVENT_CREATE", "Tạo sự kiện mới"],
            ["MARKETING_CAMPAIGN_MANAGE", "Quản lý chiến dịch marketing"],
        ],
    },
];

const QUICK_ROLE_PRESETS = {
    ADMIN: "ALL",
    MANAGER: [
        "CUSTOMER_READ", "CUSTOMER_CREATE", "CUSTOMER_UPDATE",
        "CONTRACT_READ", "CONTRACT_CREATE", "CONTRACT_UPDATE", "CONTRACT_APPROVE",
        "PAYMENT_READ", "PAYMENT_MARK_PAID",
        "REPORT_VIEW", "REPORT_EXPORT",
    ],
    SALES: [
        "CUSTOMER_READ", "CUSTOMER_CREATE", "CUSTOMER_UPDATE",
        "CONTRACT_READ", "CONTRACT_CREATE", "CONTRACT_UPDATE",
        "PAYMENT_READ", "PAYMENT_CREATE",
    ],
    SUPPORT: [
        "CUSTOMER_READ", "CONTRACT_READ", "REPORT_VIEW",
    ],
};

function RolePermissionPicker({ onChange, initialRoleName }) {
    const [allPerms, setAllPerms] = useState([]);
    const [mode, setMode] = useState(() => {
        const rn = (initialRoleName || "").toUpperCase();
        if (["ADMIN", "MANAGER", "SALES", "SUPPORT"].includes(rn)) return rn;
        return "ADMIN"; // mặc định
    });
    const [picked, setPicked] = useState(new Set());

    useEffect(() => {
        (async () => {
            const list = await fetchAllPermissions();
            setAllPerms(list);
            if (mode === "ADMIN") setPicked(new Set(list));
            else if (["MANAGER", "SALES", "SUPPORT"].includes(mode))
                setPicked(new Set(QUICK_ROLE_PRESETS[mode] || []));
            else setPicked(new Set());
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        if (!allPerms.length) return;
        if (mode === "ADMIN") setPicked(new Set(allPerms));
        else if (["MANAGER", "SALES", "SUPPORT"].includes(mode))
            setPicked(new Set(QUICK_ROLE_PRESETS[mode] || []));
        else setPicked(new Set());
    }, [mode, allPerms]);

    useEffect(() => {
        const permissions = Array.from(picked);
        if (mode === "ADMIN") onChange?.({ mode, roleName: "ADMIN", permissions: allPerms });
        else if (["MANAGER", "SALES", "SUPPORT"].includes(mode)) onChange?.({ mode, roleName: mode, permissions });
        else onChange?.({ mode: "CUSTOM", roleName: "CUSTOM", permissions });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [mode, picked, allPerms]);

    const readOnly = mode !== "CUSTOM";

    const toggle = (code) => {
        if (readOnly) return;
        const next = new Set(picked);
        if (next.has(code)) next.delete(code); else next.add(code);
        setPicked(next);
    };

    return (
        <div className="space-y-4">
            <div className="font-semibold text-[15px]">🔒 Phân quyền chi tiết</div>

            <div className="flex gap-2 flex-wrap">
                {["ADMIN","MANAGER","SALES","SUPPORT","CUSTOM"].map((r) => (
                    <button
                        key={r}
                        type="button"
                        onClick={() => setMode(r)}
                        className={`px-3 py-1 rounded-full border text-sm ${
                            mode === r ? "bg-indigo-600 text-white border-indigo-600" : "bg-white hover:bg-gray-50"
                        }`}
                    >
                        {r === "CUSTOM" ? "Tùy chỉnh" : r.charAt(0) + r.slice(1).toLowerCase()}
                    </button>
                ))}
            </div>

            <div className="space-y-4 max-h-[55vh] overflow-auto pr-2">
                {GROUPS.map((g, idx) => (
                    <div key={idx} className="rounded-xl border p-4 bg-white shadow-sm">
                        <div className="font-semibold mb-3">{g.icon} {g.title}</div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                            {g.items.map(([code, label]) => {
                                const disabled = readOnly || !allPerms.includes(code);
                                const checked = picked.has(code);
                                return (
                                    <label key={code} className={`flex items-center gap-2 ${disabled ? "opacity-60" : ""}`}>
                                        <input type="checkbox" disabled={disabled} checked={checked} onChange={() => toggle(code)} />
                                        <span>{label}</span>
                                    </label>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>

            {mode === "CUSTOM" && (
                <div className="text-xs text-gray-500">
                    Khi bấm “Lưu”, hệ thống sẽ tạo một <b>Role mới</b> gồm các quyền đã chọn rồi gán cho người dùng.
                </div>
            )}
        </div>
    );
}
